  ('diplomatic-4dfbb1fb-moex-00532', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '日本於2022年7月10日舉行參議院選舉，由自民黨、公明黨、日本維新會、國民民主黨四黨形成的「修 憲勢力」掌握177席，請問此席位數有何特殊意義？', '["自民黨繼續執政，自行提出修憲創議", "超越參議院3/4席次，該勢力可以提出修憲創議", "結合眾議院原掌握的超越2/3席次，共同提出修憲創議", "日本憲法是由當年聯合國駐日盟軍總司令部指導完成，修憲創議需送交聯合國審議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00533', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '下列何國的總統選舉參選年齡限制最低？', '["法國", "美國", "中華民國", "韓國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00534', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '比較政治研究學者以政治系統（politicalsystem）取代國家（state）概念，藉以發展科學的理論，下述 何者最接近事實？', '["解決了過往關於決策體系不透明的問題", "受到行為主義影響，發展通則化理論", "由於更加科學，所以適用在所有政體類型國家", "主張政治體系是一個從輸入、系統輸出到回饋的閉鎖行動系統"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00535', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '美國聯邦最高法院常被外界以「保守派」與「自由派」說明其成員的意識形態取向，2022年聯邦最高 法院推翻1973年「羅伊控訴韋德案」（Roev.Wade）保障墮胎權的歷史性裁決，以及判決紐約州限制 人民攜槍出家門的法律違憲，人民享有在公共場所攜帶手槍的基本權利。下述何者正確？', '["1973年「羅伊控訴韋德案」保障墮胎權是保守派大法官為多數的判決", "2022年推翻1973年「羅伊控訴韋德案」是自由派大法官為多數的判決", "2022年判決紐約州限制人民攜槍出家門的法律違憲，是保守派大法官為多數的判決", "美國聯邦最高法院由9名大法官組成，任期為8年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00536', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '2019年1月4日總統令公布之《憲法訴訟法》在2022年1月4日實施，原大法官全體審查會與憲法法庭整 合並機關化，大法官解釋改稱為「憲法法庭判決」。下述何者錯誤？', '["以憲法法庭做出判決或裁定，而非大法官會議解釋處理憲法爭議", "維持大法官2/3人數出席，出席大法官人數2/3同意為通過", "增加「專家諮詢」及「法庭之友」制度", "憲法法庭裁判書必須公開，並記載參與大法官姓名及主筆者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00537', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '根據國際非政府組織「自由之家」（FreedomHouse）發布的《2021年世界自由度報告》評估報告 顯示，政府對COVID-19疫情大流行的反應，加劇了全球民主的衰落。下述何者錯誤？', '["對政府處理疫情的政策與措施，表示反對的人面臨騷擾或刑事指控", "專制政權和民粹主義領導人致力於降低疫情透明度，助長虛假或誤導性訊息的傳播", "執政者以疫情及防疫為掩護，削弱政治反對派，鞏固權力", "民主衰落主要集中在威權國家，民主國家並不受影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00538', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '網路民主（Internet Democracy）是指運用資通訊科技提升民主政治治理，但亦有促使網路民粹主義 （InternetPopulism）或政府網路監控審查（InternetCensorship）的爭議，下述何者錯誤？', '["網際網路產生了個人的、社會的及想像的網際權力（cyber power），掌握資通訊科技的菁英成為新 統治菁英", "由於網際網路使用的普及，當代網路輿論可說是展現全意志（generalwill）的民主政治", "網路民粹主義如同傳統民粹主義，反對菁英主義，但卻又造就新菁英", "政府監控審查網際網路言論，仍須依據憲法保障言論自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00539', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '中立國家是指在發生武裝衝突時，對交戰的任何一方都不採取敵對（軍事、政治、經濟）行動的國家， 分為戰時中立國家和永久中立國家兩種。烏俄戰爭致使那些中立國家改變其中立的立場？', '["瑞士、芬蘭、奧地利", "瑞典、馬爾他、摩洛哥", "愛爾蘭、波蘭、史瓦帝尼", "瑞士、土庫曼、土耳其"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00540', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '各國政府在劃分選舉區分配席位時，主要以選舉人的身分（例如政黨、職業、性別、宗教、族裔）、 人口均數與地區（例如行政區域、地理區域）為考量，劃分為比例代表選區、單一選區及複數選區， 下述何者錯誤？', '["我國原住民立法委員選舉採單一選區，區分平地原住民及山地原住民選區", "我國直轄市議員選舉採取人口均數、行政區域劃分及婦女保障名額", "美國聯邦參議員選舉以行政區域（州）為單一選區，與人口數無關", "日本參議員選舉以行政區域（道都府縣）為選區，並混合比例代表制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00541', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-111-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '下列關於日本參議院的敘述，何者錯誤？', '["任期4年", "前身為貴族院", "每3年改選半數議員", "2022年7月剛舉行完第26屆選舉"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:43+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL)
